// CONFIGURATION: Nom du dossier cible
const DOSSIER_CIBLE = 'template rapport';

const items = $input.all();

// Chercher le dossier cible
let dossierCible = null;
const tousLesDossiers = [];

for (const item of items) {
  const data = item.json;
  if (!data || !data.id) continue;

  if (data.mimeType === 'application/vnd.google-apps.folder') {
    tousLesDossiers.push({ id: data.id, nom: data.name });

    const nomLower = (data.name || '').toLowerCase().trim();
    const cibleLower = DOSSIER_CIBLE.toLowerCase().trim();

    if (nomLower === cibleLower || 
        nomLower === cibleLower.replace(/ /g, '_') ||
        nomLower === cibleLower.replace(/ /g, '')) {
      dossierCible = { id: data.id, nom: data.name };
    }
  }
}

if (!dossierCible) {
  return [{
    json: {
      found: false,
      dossierRecherche: DOSSIER_CIBLE,
      dossiersDisponibles: tousLesDossiers.map(d => d.nom)
    }
  }];
}

return [{
  json: {
    found: true,
    dossierCible: dossierCible
  }
}];

// Récupérer les infos du dossier parent depuis le node précédent
const dossierInfo = $('Trouver Dossier').first().json.dossierCible;
const items = $input.all();

const contenu = [];

for (const item of items) {
  const data = item.json;
  if (!data || !data.id) continue;

  contenu.push({
    fichier_id: data.id,
    fichier_nom: data.name || 'Sans nom',
    fichier_type: data.mimeType === 'application/vnd.google-apps.folder' ? 'dossier' : 'fichier',
    fichier_mimeType: data.mimeType || 'unknown',
    dossier_parent_id: dossierInfo.id,
    dossier_parent_nom: dossierInfo.nom
  });
}

return [{
  json: {
    success: true,
    timestamp: new Date().toISOString(),
    dossierCible: dossierInfo,
    statistiques: {
      totalElements: contenu.length,
      sousDossiers: contenu.filter(e => e.fichier_type === 'dossier').length,
      fichiers: contenu.filter(e => e.fichier_type === 'fichier').length
    },
    contenu: contenu
  }
}];

// Dossier non trouvé
const data = $input.first().json;

return [{
  json: {
    success: false,
    timestamp: new Date().toISOString(),
    message: `Dossier '${data.dossierRecherche}' non trouvé`,
    dossiersDisponibles: data.dossiersDisponibles || [],
    contenu: []
  }
}];
